import { ButtonHTMLAttributes, forwardRef } from 'react';
import { clsx } from 'clsx';

export type ButtonVariant = 'primary' | 'secondary' | 'ghost' | 'danger' | 'success';
export type ButtonSize = 'sm' | 'md' | 'lg';

export interface ButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: ButtonVariant;
  size?: ButtonSize;
  isLoading?: boolean;
  fullWidth?: boolean;
  leftIcon?: React.ReactNode;
  rightIcon?: React.ReactNode;
}

const variantStyles: Record<ButtonVariant, string> = {
  primary: clsx(
    'bg-primary-cyan text-dark-background',
    'hover:bg-primary-cyan-light hover:shadow-glow-cyan',
    'active:scale-95',
    'disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:shadow-none',
    'transition-all duration-200'
  ),
  secondary: clsx(
    'bg-secondary-purple text-white',
    'hover:bg-secondary-purple-light hover:shadow-glow-purple',
    'active:scale-95',
    'disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:shadow-none',
    'transition-all duration-200'
  ),
  ghost: clsx(
    'bg-transparent text-primary-cyan border-2 border-primary-cyan',
    'hover:bg-primary-cyan/10 hover:shadow-glow-cyan',
    'active:scale-95',
    'disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:shadow-none',
    'transition-all duration-200'
  ),
  danger: clsx(
    'bg-accent-crimson text-white',
    'hover:bg-accent-crimson-light hover:shadow-glow-crimson',
    'active:scale-95',
    'disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:shadow-none',
    'transition-all duration-200'
  ),
  success: clsx(
    'bg-rarity-uncommon text-dark-background',
    'hover:bg-rarity-uncommon/90 hover:shadow-[0_0_20px_rgba(74,222,128,0.5)]',
    'active:scale-95',
    'disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:shadow-none',
    'transition-all duration-200'
  ),
};

const sizeStyles: Record<ButtonSize, string> = {
  sm: 'px-3 py-1.5 text-sm',
  md: 'px-4 py-2 text-base',
  lg: 'px-6 py-3 text-lg',
};

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  (
    {
      variant = 'primary',
      size = 'md',
      isLoading = false,
      fullWidth = false,
      leftIcon,
      rightIcon,
      children,
